module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output reg valid_out,
    output dout
);
wire [1:0] cnt_next;
wire [3:0] data_next;
reg [1:0] cnt;
reg [3:0] data;
assign cnt_next = cnt + 2'd1;
assign data_next = {data[2:0], data[3]};
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 2'd0;
        data <= 4'd0;
    end else begin
        if (cnt == 2'd3) begin
            data <= d;
            cnt <= 2'd0;
            valid_out <= 1'b1;
        end else begin
            cnt <= cnt_next;
            data <= data_next;
            valid_out <= 1'b0;
        end
    end
end
assign dout = data[3];
endmodule
